class Solution:
    def toHex(self, num: int) -> str:
        if num == 0: return "0"
        u = num & 0xFFFFFFFF
        digits = "0123456789abcdef"
        ans = []
        while u:
            ans.append(digits[u & 15])
            u >>= 4
        return "".join(reversed(ans))

