class Solution {
public:
    string toHex(int num) {
        if (num == 0) return "0";
        unsigned u = num;
        string d = "0123456789abcdef", ans;
        while (u) { ans.push_back(d[u & 15]); u >>= 4; }
        reverse(ans.begin(), ans.end());
        return ans;
    }
};

